const input = $input.first().json || {};
const headers = input.headers || {};

const SUPABASE_URL = String(input.supabaseUrl || '').trim();
const SUPABASE_SERVICE_ROLE_KEY = String(input.supabaseServiceRoleKey || '').trim();
const TELEGRAM_BOT_TOKEN = String(input.telegramBotToken || '').trim();
const SECRET_EXPECTED = String(input.notifyWebhookSecret || '').trim();
const SECRET_RECEIVED = String(headers['x-notify-secret'] || headers['X-Notify-Secret'] || '').trim();
const LOOKBACK_MINUTES = Number(input.lookbackMinutes || 6);
const waitSecondsRaw = Number(input.regularWaveWaitSeconds || 75);
const WAIT_SECONDS = Number.isFinite(waitSecondsRaw) ? Math.max(10, Math.min(110, waitSecondsRaw)) : 75;
const PUBLIC_BASE_URL = String(input.publicBaseUrl || 'https://cargadores-aspe.onlineexpansions.com').replace(/\/+$/, '');
const STATIC_STATION_COORDS = {
  ESIBE22E0001001: { lat: 38.341118679046346, lon: -0.7654778230267333 },
  ESIBE22E0001002: { lat: 38.3476704, lon: -0.7691027 },
  ESIBE22E0001003: { lat: 38.3498799, lon: -0.7649660 },
  ESIBE22E0001004: { lat: 38.3430059, lon: -0.7610202 },
  ESIBE22E0001005: { lat: 38.3385331, lon: -0.7766776 },
  'IBERDROLA-5629': { lat: 38.3810859, lon: -0.7308562 },
  ESIBE22E0005629: { lat: 38.3810859, lon: -0.7308562 }
};

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) throw new Error('Faltan credenciales de Supabase');
if (!TELEGRAM_BOT_TOKEN) throw new Error('Falta TELEGRAM_BOT_TOKEN');
if (SECRET_EXPECTED && SECRET_EXPECTED !== SECRET_RECEIVED) throw new Error('Webhook secret invalido');

async function requestText(url, options) {
  if (typeof fetch === 'function') {
    const response = await fetch(url, options);
    const body = await response.text();
    return { ok: response.ok, status: response.status, body: body };
  }
  const helper = this && this.helpers && this.helpers.httpRequest;
  if (typeof helper !== 'function') throw new Error('fetch no disponible en este nodo de n8n');
  const response = await helper({
    url: url,
    method: options.method || 'GET',
    headers: options.headers,
    body: options.body,
    json: false,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  return {
    ok: response.statusCode >= 200 && response.statusCode < 300,
    status: response.statusCode,
    body: typeof response.body === 'string' ? response.body : JSON.stringify(response.body || '')
  };
}

function supabaseHeaders(prefer) {
  const headersOut = {
    apikey: SUPABASE_SERVICE_ROLE_KEY,
    Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY,
    'Content-Type': 'application/json'
  };
  if (prefer) headersOut.Prefer = prefer;
  return headersOut;
}

async function supabaseGet(path) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'GET', headers: supabaseHeaders() });
  if (!response.ok) throw new Error('Supabase GET fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
  return response.body ? JSON.parse(response.body) : [];
}

async function supabasePost(path, payload, prefer) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'POST', headers: supabaseHeaders(prefer), body: JSON.stringify(payload) });
  if (!response.ok) throw new Error('Supabase POST fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
  return response.body ? JSON.parse(response.body) : [];
}

async function supabasePatch(path, payload) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'PATCH', headers: supabaseHeaders('return=minimal'), body: JSON.stringify(payload) });
  if (!response.ok) throw new Error('Supabase PATCH fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
}

async function getStationCoords(stationId) {
  try {
    const rows = await supabaseGet.call(this, 'charger_current_status?select=station_id,latitude,longitude&station_id=eq.' + encodeURIComponent(stationId) + '&limit=1');
    if (rows.length) {
      const row = rows[0] || {};
      if (Number.isFinite(Number(row.latitude)) && Number.isFinite(Number(row.longitude))) {
        return { lat: Number(row.latitude), lon: Number(row.longitude) };
      }
    }
  } catch (e) {}
  try {
    const rows = await supabaseGet.call(this, 'charger_current_status?select=station_id,lat,lng&station_id=eq.' + encodeURIComponent(stationId) + '&limit=1');
    if (rows.length) {
      const row = rows[0] || {};
      if (Number.isFinite(Number(row.lat)) && Number.isFinite(Number(row.lng))) {
        return { lat: Number(row.lat), lon: Number(row.lng) };
      }
    }
  } catch (e) {}
  const staticCoords = STATIC_STATION_COORDS[String(stationId || '')];
  if (staticCoords && Number.isFinite(Number(staticCoords.lat)) && Number.isFinite(Number(staticCoords.lon))) {
    return { lat: Number(staticCoords.lat), lon: Number(staticCoords.lon) };
  }
  return null;
}

async function sendTelegramLocation(chatId, stationId) {
  const coords = await getStationCoords.call(this, stationId);
  if (!coords) return false;
  const response = await requestText.call(this, 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendLocation', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: String(chatId), latitude: coords.lat, longitude: coords.lon })
  });
  if (!response.ok) throw new Error('Telegram sendLocation fallo: ' + response.status + ' ' + response.body);
  return true;
}

async function sendTelegram(chatId, text, replyMarkup) {
  const response = await requestText.call(this, 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: String(chatId), text: text, disable_web_page_preview: true, reply_markup: replyMarkup || undefined })
  });
  if (!response.ok) throw new Error('Telegram sendMessage fallo: ' + response.status + ' ' + response.body);
}

function buildNotificationKeyboard(eventItem) {
  return {
