function parseMaxFromZone(zone) {
  const text = String(zone || '');
  if (text.indexOf('maxlimit:') !== 0) return 0;
  const n = Number(text.split(':')[1]);
  return Number.isFinite(n) && n > 0 ? Math.floor(n) : 0;
}

async function getDispatchCount(subscriptionId) {
  const rows = await supabaseGet.call(this, 'notification_dispatches?select=id&subscription_id=eq.' + encodeURIComponent(subscriptionId) + '&limit=1000');
  return Array.isArray(rows) ? rows.length : 0;
}

function buildMessage(eventItem) {
  return '⚡ Cargador libre ahora\n\n📍 ' + eventItem.locationName + '\n🆔 ' + eventItem.stationId + '\n🔗 Ver estado: ' + PUBLIC_BASE_URL + '/charger/' + encodeURIComponent(eventItem.stationId);
}

function markPatch(sub, dispatchCountBefore) {
  const nowIso = new Date().toISOString();
  const maxNotifications = parseMaxFromZone(sub.zone);
  const countAfterSend = dispatchCountBefore + 1;
  if (sub.notify_mode === 'first_only') return { last_notified_at: nowIso, active: false };
  if (maxNotifications && countAfterSend >= maxNotifications) return { last_notified_at: nowIso, active: false };
  return { last_notified_at: nowIso };
}

const lookbackIso = new Date(Date.now() - LOOKBACK_MINUTES * 60 * 1000).toISOString();
const logs = await supabaseGet.call(this, 'charging_logs?select=id,created_at,station_id,location_name,is_available&created_at=gt.' + encodeURIComponent(lookbackIso) + '&order=station_id.asc,created_at.desc&limit=500');

const byStation = new Map();
for (const row of logs) {
  const list = byStation.get(row.station_id) || [];
  if (list.length < 2) list.push(row);
  byStation.set(row.station_id, list);
}

const freeEvents = [];
for (const pair of byStation.values()) {
  if (pair.length < 2) continue;
  const current = pair[0];
  const previous = pair[1];
  if (!previous.is_available && current.is_available) {
    freeEvents.push({
      stationId: current.station_id,
      locationName: current.location_name,
      eventKey: 'libre_ahora:' + current.station_id + ':' + current.created_at
    });
  }
}

if (!freeEvents.length) {
  return [{ json: { ok: true, info: 'Sin eventos de liberacion en esta ventana', waitSeconds: WAIT_SECONDS, pendingRegular: [] } }];
}

const nowIso = new Date().toISOString();
const pendingRegular = [];
const sentPremium = [];
const skipped = [];

for (const eventItem of freeEvents) {
  const subsPath = 'notification_subscriptions?select=id,user_id,notify_mode,zone,cooldown_minutes,last_notified_at,user:telegram_users(telegram_user_id,telegram_chat_id,telegram_username,is_premium,is_active)&active=eq.true&station_id=eq.' + encodeURIComponent(eventItem.stationId) + '&expires_at=gt.' + encodeURIComponent(nowIso) + '&limit=500';
  const subscriptions = await supabaseGet.call(this, subsPath);

  for (const sub of subscriptions) {
    const user = sub.user || {};
    const chatId = user.telegram_chat_id ? String(user.telegram_chat_id) : '';

    if (!user.is_active || !chatId) {
      skipped.push({ reason: 'usuario_inactivo_o_sin_chat_id', subscriptionId: sub.id, stationId: eventItem.stationId });
      continue;
    }

    if (sub.last_notified_at) {
      const cooldownMs = Number(sub.cooldown_minutes || 30) * 60 * 1000;
      const lastMs = new Date(sub.last_notified_at).getTime();
      if (Number.isFinite(lastMs) && Date.now() - lastMs < cooldownMs) {
        skipped.push({ reason: 'cooldown_activo', subscriptionId: sub.id, stationId: eventItem.stationId });
        continue;
      }
    }

    const maxNotifications = parseMaxFromZone(sub.zone);
    const dispatchCountBefore = maxNotifications ? await getDispatchCount.call(this, sub.id) : 0;
    if (maxNotifications && dispatchCountBefore >= maxNotifications) {
      await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(sub.id), { active: false });
      skipped.push({ reason: 'max_notificaciones_alcanzado', subscriptionId: sub.id, stationId: eventItem.stationId });
      continue;
    }

    if (user.is_premium) {
      const inserted = await supabasePost.call(this, 'notification_dispatches?on_conflict=subscription_id,event_key,wave', [{ subscription_id: sub.id, event_key: eventItem.eventKey, wave: 'priority' }], 'resolution=ignore-duplicates,return=representation');
      if (!Array.isArray(inserted) || !inserted.length) {
        skipped.push({ reason: 'dispatch_premium_duplicado', subscriptionId: sub.id, stationId: eventItem.stationId });
        continue;
      }
      await sendTelegramLocation.call(this, chatId, eventItem.stationId);
    await sendTelegram.call(this, chatId, buildMessage(eventItem), buildNotificationKeyboard(eventItem));
      await sendTelegram.call(this, chatId, buildMenuMessage(), buildMenuKeyboard());
      await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(sub.id), markPatch(sub, dispatchCountBefore));
      sentPremium.push({ subscriptionId: sub.id, stationId: eventItem.stationId, telegramUserId: user.telegram_user_id ? String(user.telegram_user_id) : null });
      continue;
    }

    pendingRegular.push({
      subscriptionId: sub.id,
      stationId: eventItem.stationId,
      locationName: eventItem.locationName,
      eventKey: eventItem.eventKey,
      telegramChatId: chatId,
      notifyMode: sub.notify_mode,
      zone: sub.zone
    });
  }
}

return [{ json: { ok: true, waitSeconds: WAIT_SECONDS, sentPremiumCount: sentPremium.length, pendingRegular: pendingRegular, skipped: skipped } }];

