let sentRegularCount = 0;
const skipped = [];
for (const item of pendingRegular) {
  if (!item.subscriptionId || !item.eventKey || !item.telegramChatId) {
    skipped.push({ reason: 'item_regular_incompleto', item: item });
    continue;
  }

  const maxNotifications = parseMaxFromZone(item.zone);
  const dispatchCountBefore = maxNotifications ? await getDispatchCount.call(this, item.subscriptionId) : 0;
  if (maxNotifications && dispatchCountBefore >= maxNotifications) {
    await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(item.subscriptionId), { active: false });
