    continue;
  }

  const inserted = await insertDispatch.call(this, item.subscriptionId, item.eventKey);
  if (!Array.isArray(inserted) || !inserted.length) {
    skipped.push({ reason: 'dispatch_regular_duplicado', subscriptionId: item.subscriptionId, stationId: item.stationId });
    continue;
  }

  await sendTelegramLocation.call(this, item.telegramChatId, item.stationId);
      await sendTelegram.call(this, item.telegramChatId, buildMessage(item), buildNotificationKeyboard(item));
  await sendTelegram.call(this, item.telegramChatId, buildMenuMessage(), buildMenuKeyboard());

  const nowIso = new Date().toISOString();
